SELECT ?answer WHERE {
  {
    ASK WHERE { <http://dbpedia.org/resource/Lahpet> <http://dbpedia.org/property/mainIngredient> <http://dbpedia.org/resource/Tea> }
  }
  UNION
  {
    SELECT DISTINCT ?ingredient WHERE { <http://dbpedia.org/resource/Kaszanka> <http://dbpedia.org/ontology/ingredient> ?ingredient }
  }
  UNION
  {
    SELECT (COUNT(DISTINCT ?country) AS ?count) WHERE {
      ?dish <http://dbpedia.org/ontology/ingredient> <http://dbpedia.org/resource/Coconut> .
      ?dish <http://dbpedia.org/property/country> ?country .
      ?country a <http://dbpedia.org/ontology/Country> .
    }
  }
}

