    }
    BIND( (EXISTS {
      <http://dbpedia.org/resource/European_Go_Federation> <http://dbpedia.org/property/membership> <http://dbpedia.org/resource/Azerbaijan>
    }) AS ?result )
  }
  UNION
  {
    BIND("Count the number of members of the organization which have Austria as one of the member ?" AS ?query)
    SELECT (COUNT(DISTINCT ?uri) AS ?result) WHERE {
      ?x <http://dbpedia.org/property/membership> <http://dbpedia.org/resource/Austria> .
      ?x <http://dbpedia.org/property/membership> ?uri .
    }
  }
  UNION
  {
    BIND("List all the members of the organization whose one of the members is Bangladesh ?" AS ?query)
    SELECT DISTINCT ?result WHERE {
      ?x <http://dbpedia.org/property/membership> <http://dbpedia.org/resource/Bangladesh> .
      ?x <http://dbpedia.org/property/membership> ?result .
      ?x a <http://dbpedia.org/ontology/Organisation> .
    }
  }
}
LIMIT 100

