SELECT ?question ?answer WHERE {
  VALUES (?question) {
    ("Does chicago own the washington station on the CTA Blue Line?")
    ("Who currently operates the railway lines one of whose stockholder is Chicago, St Paul, Minneapolis and Omaha railway?")
    ("Which board memeber of jimmy Wales also owns Latvian Wikipedia ?")
  }
  OPTIONAL {
    FILTER(?question = "Does chicago own the washington station on the CTA Blue Line?")
    BIND(
      EXISTS {
        <http://dbpedia.org/resource/Washington_station_(CTA_Blue_Line)> <http://dbpedia.org/property/owned> <http://dbpedia.org/resource/Chicago>
      } AS ?answer
    )
  }
  OPTIONAL {
    FILTER(?question = "Who currently operates the railway lines one of whose stockholder is Chicago, St Paul, Minneapolis and Omaha railway?")
    SELECT DISTINCT ?answer WHERE {
      ?x <http://dbpedia.org/property/owner> <http://dbpedia.org/resource/Chicago,_St._Paul,_Minneapolis_and_Omaha_Railway> .
      ?x <http://dbpedia.org/ontology/operatedBy> ?answer .
      ?x a <http://dbpedia.org/ontology/RailwayLine> .
    }
    LIMIT 1
  }
  OPTIONAL {
    FILTER(?question = "Which board memeber of jimmy Wales also owns Latvian Wikipedia ?")
    SELECT DISTINCT ?answer WHERE {
      <http://dbpedia.org/resource/Jimmy_Wales> <http://dbpedia.org/ontology/board> ?answer .
      <http://dbpedia.org/resource/Latvian_Wikipedia> <http://dbpedia.org/ontology/owner> ?answer .
    }
    LIMIT 1
  }
}

