SELECT ?question ?answer WHERE {
  VALUES (?question ?person ?predicate ?guitar ?guitarLabel) {
    ("Was Duanne Allman famous for playing the Gibson SG?" <http://dbpedia.org/resource/Duane_Allman> <http://dbpedia.org/property/notableInstruments> <http://dbpedia.org/resource/Gibson_SG> "Gibson SG")
    ("Does Kirk Hammett play the Gibson Flying V?" <http://dbpedia.org/resource/Kirk_Hammett> <http://dbpedia.org/ontology/instrument> <http://dbpedia.org/resource/Gibson_Flying_V> "Gibson Flying V")
  }
  OPTIONAL {
    ?person ?predicate ?guitar .
  }
  BIND(IF(BOUND(?guitar), "YES", "NO") AS ?answer)
}
UNION
{
  SELECT ("How many people are famous for the Gibson Les Paul?" AS ?question) (STR(COUNT(DISTINCT ?person)) AS ?answer) WHERE {
    ?person <http://dbpedia.org/property/notableInstruments> <http://dbpedia.org/resource/Gibson_Les_Paul> .
  }
}

