SELECT ?question ?answer WHERE {
  {
    BIND("Is the Providence Chapel, Charlwood made in New English style of architecture?" AS ?question)
    ASK {
      <http://dbpedia.org/resource/Providence_Chapel,_Charlwood> <http://dbpedia.org/property/style> <http://dbpedia.org/resource/New_England> .
    }
    BIND(IF(
      EXISTS {
        <http://dbpedia.org/resource/Providence_Chapel,_Charlwood> <http://dbpedia.org/property/style> <http://dbpedia.org/resource/New_England> .
      }, "Yes", "No") AS ?answer)
  }
  UNION
  {
    BIND("WHich region of the Providence Chapel, Charlwood is also the region of the Joseph Case High School" AS ?question)
    SELECT DISTINCT ?answer WHERE {
      <http://dbpedia.org/resource/Providence_Chapel,_Charlwood> <http://dbpedia.org/ontology/region> ?answer.
      <http://dbpedia.org/resource/Joseph_Case_High_School> <http://dbpedia.org/ontology/region> ?answer.
    } LIMIT 1
  }
  UNION
  {
    BIND("Is the Mount St Peter Church made in the international architectural style?" AS ?question)
    ASK {
      <http://dbpedia.org/resource/Mount_St._Peter_Church> <http://dbpedia.org/property/architecture> <http://dbpedia.org/resource/International_Style_(architecture)> .
    }
    BIND(IF(
      EXISTS {
        <http://dbpedia.org/resource/Mount_St._Peter_Church> <http://dbpedia.org/property/architecture> <http://dbpedia.org/resource/International_Style_(architecture)> .
      }, "Yes", "No") AS ?answer)
  }
}

