PREFIX  owl:  <http://www.w3.org/2002/07/owl#>
PREFIX  dc:   <http://purl.org/dc/elements/1.1/>

SELECT DISTINCT  ?person
WHERE
  {   { ?company  <http://dbpedia.org/property/foundationPlace>  <http://dbpedia.org/resource/New_York_(state)> .
        ?person   <http://dbpedia.org/ontology/board>  ?company ;
                  rdf:type              <http://dbpedia.org/ontology/Person>
      }
    UNION
      { ?person  <http://dbpedia.org/property/placeOfBirth>  <http://dbpedia.org/resource/Harriman,_New_York> ;
                 rdf:type              <http://dbpedia.org/ontology/MusicalArtist>
      }
    UNION
      { ?play    <http://dbpedia.org/property/place>  <http://dbpedia.org/resource/New_York_City> ;
                 rdf:type              <http://dbpedia.org/ontology/Play> ;
                 <http://dbpedia.org/property/starring>  ?person .
        ?person  rdf:type              <http://dbpedia.org/ontology/Actor>
      }
  }

